using namespace std;


int firstOne(vector<int> &row, int low, int high) {
    while (low <= high) {
        int mid = low + (high - low) / 2;
        if ((mid == 0 || row[mid - 1] == 0) && row[mid] == 1)
            return mid;
        else if (row[mid] == 0)
            return firstOne(row, mid + 1, high);
        else
            return firstOne(row, low, mid - 1);
    }
    return -1; 
}

int maxOneRow(vector<vector<int>>& mat) {

    int m = mat.size();
    int n = mat[0].size();

    int maxones = 0, row = 0;
